const API_BASE = 'https://api.coingecko.com/api/v3';
const CACHE_DURATION = 60000;
let cache = { data: null, timestamp: null };
let autoRefreshEnabled = true;

async function fetchCryptoData() {
    // Check cache first
    if (cache.data && Date.now() - cache.timestamp < CACHE_DURATION) {
        return cache.data;
    }

    const response = await fetchWithTimeout(
        `${API_BASE}/coins/markets?vs_currency=usd&order=market_cap_desc&per_page=20`,
        10000
    );
    if (!response.ok) throw new Error(`HTTP ${response.status}`);

    const data = await response.json();
    cache = { data, timestamp: Date.now() };
    return data;
}

async function loadAndDisplayData() {
    try {
        showSkeletonCards();
        const coins = await fetchCryptoData();
        displayMarketStats(coins);
        displayCryptoCards(coins);
        updateTimestamp();
    } catch (error) {
        showError(error.message);
    }
}

// Auto-refresh, pause when tab hidden
document.addEventListener('visibilitychange', () => {
    if (document.hidden) stopAutoRefresh();
    else if (autoRefreshEnabled) startAutoRefresh();
});

